+    return static_cast<ImageScore*>(conf->image_score)->persist(image_location);
+}
+
+JNIEXPORT void image_score_reset(struct crlib_conf* conf) {
+    static_cast<ImageScore*>(conf->image_score)->reset_all();
+}
+
+JNIEXPORT const crlib_extension_t *find_extension(crlib_extension_t * const *extensions, const char *name, size_t size) {
+  for (crlib_extension_t * const *ext = extensions; *ext != nullptr; ++ext) {
+    if (strcmp(name, (*ext)->name) == 0) {
+      if (size <= (*ext)->size) {
+        return *ext;
+      }
+      return nullptr;
+    }
+  }
+  return nullptr;
+}
