+#include <cerrno>
+#include <clocale>
+#include <cstdio>
+#include <cstring>
+#ifdef MACOSX
+#include <locale.h>
+#include <xlocale.h>
+#endif // MACOSX
+
+#include "crcommon.hpp"
+#include "hashtable.hpp"
+#include "image_score.hpp"
+
+bool ImageScore::persist(const char* image_location) const {
+  char fname[PATH_MAX];
+  if (snprintf(fname, sizeof(fname), "%s/score", image_location) >= (int) sizeof(fname) - 1) {
+    LOG("filename too long: %s/score", image_location);
+    return false;
+  }
+  FILE* f = fopen(fname, "w");
+  if (f == nullptr) {
+    LOG("cannot open %s for writing: %s", fname, strerror(errno));
+    return false;
+  }
+  auto close_f = defer([&] {
+    if (fclose(f)) {
+     LOG("cannot close %s/score: %s", image_location, strerror(errno));
+    }
+  });
+  // Handle duplicates
+  bool result = true;
+  const char **keys = new(std::nothrow) const char*[_score.size()];
+  if (keys == nullptr) {
+    LOG("cannot allocate array of metrics");
+    return false;
+  }
+  auto delete_keys = defer([&] { delete[] keys; });
+  size_t index = 0;
+  _score.foreach([&](const Score& score){
+    keys[index++] = score._name;
+  });
+  Hashtable<double> ht(keys, _score.size(), _score.size() * 3 / 2);
+  if (!ht.is_initialized()) {
+    LOG("cannot create score hashtable (allocation failure)");
+    return false;
+  }
+  _score.foreach([&](const Score& score) {
+    ht.put(score._name, score._value);
+  });
+#ifndef _WINDOWS
+  // C locale uses '.' as decimal point for floating-point values
+  // (some other locales use ',').
+  // Ignore error, the reset with local 0 will be a noop
+  locale_t c_locale = newlocale(LC_ALL_MASK, "C", 0);
+  locale_t old_locale = uselocale(c_locale);
+#endif // _WINDOWS
+  ht.foreach([&](const char *key, double value){
+    fprintf(f, "%s=%f\n", key, value);
+  });
+#ifndef _WINDOWS
+  uselocale(old_locale);
+  freelocale(c_locale);
+#endif
+  return result;
+}

